/**
 * Focus management utilities for the modal component.
 */

/** CSS selectors for natively focusable elements. */
export const FOCUSABLE_SELECTORS = [
  'a[href]',
  'area[href]',
  'button:not([disabled])',
  'input:not([disabled])',
  'select:not([disabled])',
  'textarea:not([disabled])',
  'iframe',
  '[tabindex]:not([tabindex="-1"])',
  '[contenteditable="true"]',
].join(',');

/**
 * Gets the deepest active element by traversing through shadow roots.
 */
export function getDeepActiveElement(): HTMLElement | null {
  let active: HTMLElement | null = document.activeElement as HTMLElement;

  while (active?.shadowRoot?.activeElement) {
    active = active.shadowRoot.activeElement as HTMLElement;
  }

  return active;
}

/**
 * Finds all focusable elements within a container, traversing shadow DOM and slots.
 */
export function findFocusableElements(root: Element | ShadowRoot): HTMLElement[] {
  const elements: HTMLElement[] = [];
  const seen = new WeakSet<HTMLElement>();

  function walk(node: Element | ShadowRoot) {
    const children = 'children' in node ? Array.from(node.children) : [];

    for (const child of children) {
      const el = child as HTMLElement;

      // Add if focusable and visible
      if (el.matches?.(FOCUSABLE_SELECTORS) && _isVisible(el) && !seen.has(el)) {
        seen.add(el);
        elements.push(el);
      }

      // Traverse shadow root
      if (el.shadowRoot) {
        walk(el.shadowRoot);
      }

      // Handle native slots - traverse assigned elements
      if (child.tagName === 'SLOT') {
        for (const assigned of (child as HTMLSlotElement).assignedElements({ flatten: true })) {
          const assignedEl = assigned as HTMLElement;
          if (assignedEl.matches?.(FOCUSABLE_SELECTORS) && _isVisible(assignedEl) && !seen.has(assignedEl)) {
            seen.add(assignedEl);
            elements.push(assignedEl);
          }
          if (assignedEl.shadowRoot) {
            walk(assignedEl.shadowRoot);
          }
          walk(assigned);
        }
      }

      // Continue to children
      walk(child);
    }
  }

  walk(root);

  return elements;
}

/**
 * Checks if an element is visible, traversing across shadow DOM boundaries.
 */
function _isVisible(el: HTMLElement): boolean {
  let current: HTMLElement | null = el;

  while (current) {
    if (current.hasAttribute('hidden')) {
      return false;
    }

    try {
      const style = getComputedStyle(current);
      if (style.display === 'none' || style.visibility === 'hidden') {
        return false;
      }
    } catch {}

    // Traverse up, crossing shadow DOM boundaries
    if (current.parentElement) {
      current = current.parentElement;
    } else {
      const root = current.getRootNode();
      current = root instanceof ShadowRoot ? (root.host as HTMLElement) : null;
    }
  }

  return true;
}

/**
 * Finds an element by selector, searching through shadow DOM.
 */
export function findElementBySelector(root: HTMLElement, selector: string): HTMLElement | null {
  // Try light DOM first
  const lightEl = root.querySelector<HTMLElement>(selector);
  if (lightEl) return lightEl;

  // Try shadow DOM
  const shadowEl = root.shadowRoot?.querySelector<HTMLElement>(selector);
  if (shadowEl) return shadowEl;

  // Deep search through nested shadow roots
  function deepSearch(el: Element): HTMLElement | null {
    if (el.shadowRoot) {
      const found = el.shadowRoot.querySelector<HTMLElement>(selector);
      if (found) return found;

      for (const child of Array.from(el.shadowRoot.querySelectorAll('*'))) {
        const result = deepSearch(child);
        if (result) return result;
      }
    }

    return null;
  }

  return deepSearch(root);
}

/**
 * Gets a focusable element from a target (handles shadow DOM hosts).
 */
export function getFocusableTarget(target: HTMLElement): HTMLElement {
  if (target.matches(FOCUSABLE_SELECTORS)) {
    return target;
  }

  // Check shadow root for focusable element
  const shadowFocusable = target.shadowRoot?.querySelector<HTMLElement>(FOCUSABLE_SELECTORS);
  if (shadowFocusable) return shadowFocusable;

  // Check children
  const childFocusable = target.querySelector<HTMLElement>(FOCUSABLE_SELECTORS);
  if (childFocusable) return childFocusable;

  // Make target focusable as fallback
  if (!target.hasAttribute('tabindex')) {
    target.setAttribute('tabindex', '-1');
  }

  return target;
}

/**
 * Finds the modal's heading element (h1-h6), prioritizing modal header.
 */
export function findHeadingElement(root: HTMLElement): HTMLElement | null {
  const headingSelector = 'h1, h2, h3, h4, h5, h6';

  // Check wdpr-modal-header first
  const modalHeader = root.querySelector('wdpr-modal-header');
  const headerHeading = modalHeader?.shadowRoot?.querySelector<HTMLElement>(headingSelector);
  if (headerHeading) return headerHeading;

  // Check direct children's shadow roots
  for (const child of Array.from(root.children)) {
    const shadowHeading = (child as HTMLElement).shadowRoot?.querySelector<HTMLElement>(headingSelector);
    if (shadowHeading) return shadowHeading;
  }

  // Check light DOM
  const lightHeading = root.querySelector<HTMLElement>(headingSelector);
  if (lightHeading) return lightHeading;

  // Deep search as fallback
  for (const el of Array.from(root.querySelectorAll('*'))) {
    const shadowHeading = (el as HTMLElement).shadowRoot?.querySelector<HTMLElement>(headingSelector);
    if (shadowHeading) return shadowHeading;
  }

  return null;
}
